CREATE TYPE "Role" AS ENUM ('USER','ADMIN'); CREATE TYPE "Faction" AS ENUM ('IRONVALE','ARCANUM','NEUTRAL'); CREATE TYPE "CardType" AS ENUM ('UNIT','SPELL','TRAP','TERRAIN','EQUIPMENT'); CREATE TYPE "Rarity" AS ENUM ('COMMON','UNCOMMON','RARE','EPIC','LEGENDARY','MYTHIC');
CREATE TABLE "User"("id" TEXT PRIMARY KEY,"email" TEXT NOT NULL UNIQUE,"passwordHash" TEXT NOT NULL,"role" "Role" NOT NULL DEFAULT 'USER',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "UserProfile"("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL UNIQUE REFERENCES "User"("id") ON DELETE CASCADE,"displayName" TEXT NOT NULL,"avatarUrl" TEXT,"level" INTEGER NOT NULL DEFAULT 1);
CREATE TABLE "RefreshToken"("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"tokenHash" TEXT NOT NULL UNIQUE,"expiresAt" TIMESTAMP(3) NOT NULL,"revokedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "CardSet"("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL);
CREATE TABLE "Card"("id" TEXT PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"description" TEXT NOT NULL,"type" "CardType" NOT NULL,"faction" "Faction" NOT NULL,"rarity" "Rarity" NOT NULL,"cost" INTEGER NOT NULL,"attack" INTEGER,"health" INTEGER,"keywords" JSONB NOT NULL,"collectible" BOOLEAN NOT NULL DEFAULT true,"setId" TEXT NOT NULL REFERENCES "CardSet"("id"));
CREATE TABLE "UserCard"("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"cardId" TEXT NOT NULL REFERENCES "Card"("id") ON DELETE CASCADE,"quantity" INTEGER NOT NULL DEFAULT 0,PRIMARY KEY("userId","cardId"));
CREATE TABLE "Deck"("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE,"name" TEXT NOT NULL,"faction" "Faction" NOT NULL,"isDefault" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "DeckCard"("deckId" TEXT NOT NULL REFERENCES "Deck"("id") ON DELETE CASCADE,"cardId" TEXT NOT NULL REFERENCES "Card"("id"),"quantity" INTEGER NOT NULL,"position" INTEGER NOT NULL,PRIMARY KEY("deckId","cardId"),UNIQUE("deckId","position"));
CREATE INDEX "RefreshToken_userId_idx" ON "RefreshToken"("userId"); CREATE INDEX "Card_filter_idx" ON "Card"("faction","type","rarity","cost"); CREATE INDEX "Deck_userId_idx" ON "Deck"("userId");
